import{_ as d,o as a,c as r,ag as e}from"./chunks/framework.uOkKsJ4G.js";const u=JSON.parse('{"title":"功能介绍","description":"Narrafiilm 全部功能的详细说明。","frontmatter":{"title":"功能介绍","description":"Narrafiilm 全部功能的详细说明。"},"headers":[],"relativePath":"features.md","filePath":"features.md","lastUpdated":1775974279000}'),h={name:"features.md"};function o(l,t,i,n,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="功能介绍" tabindex="-1">功能介绍 <a class="header-anchor" href="#功能介绍" aria-label="Permalink to &quot;功能介绍&quot;">​</a></h1><p>Narrafiilm 的核心只有一个：<strong>将含明确主角的视频，转化为第一人称配音解说</strong>。以下所有功能都围绕这一核心展开。</p><hr><h2 id="核心工作流" tabindex="-1">核心工作流 <a class="header-anchor" href="#核心工作流" aria-label="Permalink to &quot;核心工作流&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>视频 → Qwen2.5-VL 场景理解 → DeepSeek-V3 解说生成 → Edge-TTS 配音 → ASS 字幕 → MP4 / 剪映草稿</span></span></code></pre></div><hr><h2 id="场景理解" tabindex="-1">场景理解 <a class="header-anchor" href="#场景理解" aria-label="Permalink to &quot;场景理解&quot;">​</a></h2><p><strong>Qwen2.5-VL（7B）</strong> 逐帧抽帧分析，识别：</p><ul><li>主角的外貌、动作、行为意图</li><li>场景地点和环境氛围</li><li>画面中的关键物体及空间关系</li><li>事件发展的叙事逻辑</li></ul><p>抽帧密度可配置（默认每秒 1 帧），支持长视频分段处理。</p><hr><h2 id="第一人称解说生成" tabindex="-1">第一人称解说生成 <a class="header-anchor" href="#第一人称解说生成" aria-label="Permalink to &quot;第一人称解说生成&quot;">​</a></h2><p><strong>DeepSeek-V3.2</strong> 基于场景理解结果，用&quot;我&quot;的视角撰写解说稿。</p><h3 id="解说风格-情感模式" tabindex="-1">解说风格（情感模式） <a class="header-anchor" href="#解说风格-情感模式" aria-label="Permalink to &quot;解说风格（情感模式）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>风格</th><th>适用场景</th><th>解说语气</th></tr></thead><tbody><tr><td>治愈</td><td>旅行、自然风光、生活记录</td><td>温暖、放松、随性</td></tr><tr><td>悬疑</td><td>惊悚、探秘、推理向内容</td><td>低沉、留白、制造紧张感</td></tr><tr><td>励志</td><td>挑战、成长、努力过程</td><td>坚定、有力、积极</td></tr><tr><td>怀旧</td><td>回忆、老物件、时光流逝</td><td>柔和、感慨、余韵悠长</td></tr><tr><td>浪漫</td><td>情感、约会、美好时刻</td><td>细腻、温柔、充满画面感</td></tr></tbody></table><h3 id="解说长度控制" tabindex="-1">解说长度控制 <a class="header-anchor" href="#解说长度控制" aria-label="Permalink to &quot;解说长度控制&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>每段字数</th><th>适用场景</th></tr></thead><tbody><tr><td>简洁版</td><td>30–60 字</td><td>短视频（&lt;1 分钟）</td></tr><tr><td>标准版</td><td>60–120 字</td><td>3–10 分钟视频</td></tr><tr><td>详细版</td><td>120–200 字</td><td>纪录片风格</td></tr></tbody></table><hr><h2 id="配音合成" tabindex="-1">配音合成 <a class="header-anchor" href="#配音合成" aria-label="Permalink to &quot;配音合成&quot;">​</a></h2><h3 id="edge-tts-默认" tabindex="-1">Edge-TTS（默认） <a class="header-anchor" href="#edge-tts-默认" aria-label="Permalink to &quot;Edge-TTS（默认）&quot;">​</a></h3><p>微软主流 TTS 引擎，无需 API Key，免费使用，支持中文多音色：</p><table tabindex="0"><thead><tr><th>音色</th><th>风格</th><th>适用</th></tr></thead><tbody><tr><td><code>zh-CN-Xiaoxiao</code></td><td>女声，清晰自然</td><td>通用场景</td></tr><tr><td><code>zh-CN-Yunxi</code></td><td>男声，成熟稳重</td><td>叙事为主</td></tr><tr><td><code>zh-CN-Xiaoyi</code></td><td>女声，活泼轻柔</td><td>治愈风格</td></tr><tr><td><code>zh-CN-Yunyang</code></td><td>男声，专业正式</td><td>新闻/课程</td></tr></tbody></table><h3 id="f5-tts-可选" tabindex="-1">F5-TTS（可选） <a class="header-anchor" href="#f5-tts-可选" aria-label="Permalink to &quot;F5-TTS（可选）&quot;">​</a></h3><p>零样本音色克隆，只需 15–30 秒参考音频，即可克隆任意音色。</p><blockquote><p>F5-TTS 需要独立安装，详见<a href="./guide/installation.html#f5-tts-音色克隆">安装指南</a>。</p></blockquote><h3 id="语速与音调" tabindex="-1">语速与音调 <a class="header-anchor" href="#语速与音调" aria-label="Permalink to &quot;语速与音调&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>范围</th><th>默认值</th></tr></thead><tbody><tr><td>语速</td><td>0.6x – 1.5x</td><td>1.0x</td></tr><tr><td>音调</td><td>-50% – +50%</td><td>0</td></tr></tbody></table><hr><h2 id="精准字幕" tabindex="-1">精准字幕 <a class="header-anchor" href="#精准字幕" aria-label="Permalink to &quot;精准字幕&quot;">​</a></h2><p>基于 TTS word-level timing 的音字同步，字幕精确到每个字的起止时间（50ms 以内精度）。</p><h3 id="字幕样式" tabindex="-1">字幕样式 <a class="header-anchor" href="#字幕样式" aria-label="Permalink to &quot;字幕样式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>样式</th><th>效果</th></tr></thead><tbody><tr><td><strong>电影黑底白字</strong></td><td>底部居中，黑底白字，带淡淡描边</td></tr><tr><td><strong>透明覆盖</strong></td><td>底部居中，无背景，文字描边</td></tr><tr><td><strong>卡片式</strong></td><td>全宽底栏，半透明背景</td></tr><tr><td><strong>顶部字幕</strong></td><td>用于说明画面外事件</td></tr></tbody></table><h3 id="ass-高级样式" tabindex="-1">ASS 高级样式 <a class="header-anchor" href="#ass-高级样式" aria-label="Permalink to &quot;ASS 高级样式&quot;">​</a></h3><ul><li>字体大小、行数、位置可调</li><li>一次只显示一行（KTV 模式）</li><li>可叠加解说词 + 环境音文字说明</li></ul><hr><h2 id="导出格式" tabindex="-1">导出格式 <a class="header-anchor" href="#导出格式" aria-label="Permalink to &quot;导出格式&quot;">​</a></h2><h3 id="mp4-直接输出" tabindex="-1">MP4（直接输出） <a class="header-anchor" href="#mp4-直接输出" aria-label="Permalink to &quot;MP4（直接输出）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>说明</th></tr></thead><tbody><tr><td>编码</td><td>H.264（兼容性好）或 H.265（体积小约 40%）</td></tr><tr><td>分辨率</td><td>保持原片或指定缩放（1080p / 720p / 480p）</td></tr><tr><td>帧率</td><td>保持原片帧率</td></tr><tr><td>音轨</td><td>配音 + 可选保留原音</td></tr></tbody></table><h3 id="剪映草稿-json-继续精剪" tabindex="-1">剪映草稿 JSON（继续精剪） <a class="header-anchor" href="#剪映草稿-json-继续精剪" aria-label="Permalink to &quot;剪映草稿 JSON（继续精剪）&quot;">​</a></h3><p>导出原生 <code>.draft.json</code>，直接导入剪映继续编辑，保留：</p><ul><li>时间轴和分割点</li><li>字幕轨道（可继续调整）</li><li>配音轨道</li></ul><hr><h2 id="支持的视频格式" tabindex="-1">支持的视频格式 <a class="header-anchor" href="#支持的视频格式" aria-label="Permalink to &quot;支持的视频格式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>格式</th><th>扩展名</th><th>推荐度</th></tr></thead><tbody><tr><td>MP4</td><td><code>.mp4</code></td><td>高，兼容性最好</td></tr><tr><td>MOV</td><td><code>.mov</code></td><td>高，macOS 录制格式</td></tr><tr><td>MKV</td><td><code>.mkv</code></td><td>中，支持多音轨</td></tr><tr><td>AVI</td><td><code>.avi</code></td><td>低，体积较大</td></tr><tr><td>WebM</td><td><code>.webm</code></td><td>低，部分编码有限制</td></tr></tbody></table><blockquote><p><strong>不支持 GIF</strong>。GIF 请先转换为 MP4。</p></blockquote><hr><h2 id="配置选项总览" tabindex="-1">配置选项总览 <a class="header-anchor" href="#配置选项总览" aria-label="Permalink to &quot;配置选项总览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类别</th><th>选项</th><th>默认值</th></tr></thead><tbody><tr><td><strong>场景理解</strong></td><td>抽帧间隔</td><td>1 秒</td></tr><tr><td></td><td>场景分段最小长度</td><td>3 秒</td></tr><tr><td><strong>解说生成</strong></td><td>情感风格</td><td>治愈</td></tr><tr><td></td><td>解说长度</td><td>标准版</td></tr><tr><td></td><td>是否保留原音</td><td>否</td></tr><tr><td><strong>配音</strong></td><td>TTS 引擎</td><td>Edge-TTS</td></tr><tr><td></td><td>音色</td><td>XiaoXiao（女声）</td></tr><tr><td></td><td>语速</td><td>1.0x</td></tr><tr><td></td><td>音调</td><td>0</td></tr><tr><td><strong>字幕</strong></td><td>样式</td><td>电影黑底白字</td></tr><tr><td></td><td>是否启用</td><td>是</td></tr><tr><td><strong>导出</strong></td><td>视频编码</td><td>H.264</td></tr><tr><td></td><td>分辨率</td><td>保持原片</td></tr><tr><td></td><td>格式</td><td>MP4</td></tr></tbody></table><hr><h2 id="硬件与性能" tabindex="-1">硬件与性能 <a class="header-anchor" href="#硬件与性能" aria-label="Permalink to &quot;硬件与性能&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段（5 分钟视频）</th><th>CPU 模式</th><th>GPU 加速</th></tr></thead><tbody><tr><td>视频分析</td><td>约 15–20 分钟</td><td>约 3–5 分钟</td></tr><tr><td>解说生成</td><td>约 30 秒</td><td>约 30 秒</td></tr><tr><td>配音合成</td><td>约 2 分钟</td><td>约 2 分钟</td></tr><tr><td>字幕制作</td><td>约 1 分钟</td><td>约 1 分钟</td></tr><tr><td>视频导出</td><td>约 5–10 分钟</td><td>约 2–3 分钟</td></tr></tbody></table><p>系统自动检测 CUDA，可用时自动启用 GPU 加速，无 GPU 时回退 CPU。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./guide/quick-start.html">5 分钟快速开始</a> — 快速上手指南</li><li><a href="./guide/installation.html">安装配置</a> — 各平台完整安装步骤</li><li><a href="./guide/exporting.html">导出格式</a> — 详细导出参数配置</li><li><a href="./faq.html">常见问题</a> — 常见问题解答</li></ul>',55)])])}const p=d(h,[["render",o]]);export{u as __pageData,p as default};
